import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./UserPages.module.css";

const PackageDetailsPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  // PACKAGE
  const [pkg, setPkg] = useState(null);
  const [loading, setLoading] = useState(true);

  // REVIEWS
  const [reviews, setReviews] = useState([]);
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");

  // FETCH PACKAGE
  useEffect(() => {
    api.get(`/packages/${id}`)
      .then((res) => setPkg(res.data.data))
      .catch((err) => console.error(err))
      .finally(() => setLoading(false));
  }, [id]);

  // ✅ FETCH REVIEWS FROM DB
  const fetchReviews = async () => {
    try {
      const res = await api.get("/reviews");
      const filtered = res.data.filter(
        (r) => r.package?._id === id
      );
      setReviews(filtered);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchReviews();
  }, [id]);

  // ✅ SUBMIT REVIEW TO DB
  const handleSubmit = async () => {
    if (!comment) return alert("Enter comment");

    try {
      await api.post("/reviews", {
        rating,
        comment,
        packageId: id
      });

      setComment("");
      setRating(5);

      fetchReviews(); // refresh
    } catch (err) {
      console.log(err);
    }
  };

  // LOADING
  if (loading) return <p>Loading...</p>;
  if (!pkg) return <p>Package not found</p>;

  return (
    <>
      <Navbar />

      <div className={styles.detailsContainer}>

        {/* HERO */}
        <div className={styles.detailsHero}>
          <h1>{pkg.name}</h1>
          <span className={styles.badge}>{pkg.duration}</span>
          <p>{pkg.description || "Enjoy your trip!"}</p>
        </div>

        {/* HOTELS */}
        <h2>🏨 Available Hotels</h2>

        <div className={styles.hotelGrid}>
          {pkg.hotels?.map((hotel, index) => (
            <div key={index} className={styles.hotelCard}>

              <img
                src={
                  hotel.image ||
                  "https://images.unsplash.com/photo-1566073771259-6a8506099945"
                }
                alt={hotel.name}
              />

              <h4>{hotel.name}</h4>
              <p>₹{hotel.pricePerDay}</p>
              <p>{hotel.description}</p>

              <button
                onClick={() =>
                  navigate("/payment", {
                    state: { package: pkg, hotel }
                  })
                }
              >
                Select Hotel
              </button>

            </div>
          ))}
        </div>

        {/* ⭐ REVIEWS */}
        <div className={styles.reviews}>
          <h2>⭐ Customer Reviews</h2>

          {/* RATING */}
          <select
            className={styles.input}
            value={rating}
            onChange={(e) => setRating(Number(e.target.value))}
          >
            <option value={5}>⭐⭐⭐⭐⭐</option>
            <option value={4}>⭐⭐⭐⭐</option>
            <option value={3}>⭐⭐⭐</option>
            <option value={2}>⭐⭐</option>
            <option value={1}>⭐</option>
          </select>

          {/* COMMENT */}
          <textarea
            placeholder="Write your experience..."
            className={styles.textarea}
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />

          <button className={styles.reviewBtn} onClick={handleSubmit}>
            Submit Review
          </button>

          {/* SHOW REVIEWS FROM DB */}
          {reviews.length === 0 ? (
            <p className={styles.noReview}>No reviews yet.</p>
          ) : (
            <div className={styles.reviewList}>
              {reviews.map((r) => (
                <div key={r._id} className={styles.reviewCard}>
                  <h4>{r.user?.name}</h4>
                  <p>{"⭐".repeat(r.rating)}</p>
                  <p>{r.comment}</p>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </>
  );
};

export default PackageDetailsPage;
